const SPELL_INDEX = Object.fromEntries(SPELL_DATA.map((spell) => [spell.key, spell]));
const SPELL_NAMES = SPELL_DATA.map((spell) => spell.name);

function normalizeSpellLookupName(value) {
  return String(value || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/gi, ' ').trim().toLowerCase();
}

function getSpellInfo(name) {
  return SPELL_INDEX[normalizeSpellLookupName(typeof name === 'string' ? name : name?.name)];
}

function getSpellNamesForClass(className) {
  const normalizedClass = String(className || '').toLowerCase();
  return SPELL_DATA.filter((spell) => spell.classes.some((spellClass) => spellClass.toLowerCase() === normalizedClass)).map((spell) => spell.name);
}

if (typeof globalThis !== 'undefined') {
  globalThis.SPELL_DATA = SPELL_DATA;
  globalThis.getSpellInfo = getSpellInfo;
  globalThis.getSpellNamesForClass = getSpellNamesForClass;
}
